mapper.select:
SELECT T1.ID, T1.TRUST_ID, tdsi.TRUST_INFO_NO, T1.WORK_DATE, T1.CLASS_CODE, T1.CLASS_NAME, T8.TARGET_CD, T8.TARGET_NM, T8.SOURCE_CD, T8.SOURCE_NM, T1.PROCESS_CODE, T1.PROCESS_NAME, T1.SHIPVOYAGE_ID, T1.SHIPVOYAGE_ITEM_ID, NVL(T5.SHIP_NAME,tdsi.SHIP_NAME) SHIP_NAME, T7."shipNameVoyage", NVL(T4.VOYAGE,T7.VOYAGE) VOYAGE, NVL(T5.SCN,T7.SCN) SCN, T1.HATCH, T4.LOAD_UNLOAD, T1.BERTH_ID, T1.BERTH_NAME, 5 AS HATCH_NUM, T1.PLAN_NO, T1.PLAN_TYPE, T2.NUM AS LABOR_NUM, T1.STATUS, M1.NM AS STATUS_LABEL, T1.RESHIPMENT_TYPE_CODE, M2.NM AS RESHIPMENT_TYPE_Label, T8.IS_DIRECT_ACCESS, T1.FRONT_TALLY_BY, T1.COMPANY_ID, T1.COMPANY_NAME, tbtc2.PACKING_CODE, tbtc2.PACKING_NAME FROM T_PRD_WORK_PLAN T1 LEFT JOIN T_BUS_TRUST TBT ON T1.TRUST_ID = TBT.ID LEFT JOIN T_PRD_DISPATCH T2 ON T1. ID = T2.WORK_PLAN_ID AND T2.DISPATCH_TYPE = '2' LEFT JOIN m_constants M1 ON T1.STATUS = M1.CD AND M1.TYPE_CD = 'WORK_PLAN_STATUS' LEFT JOIN m_constants M2 ON T1.RESHIPMENT_TYPE_CODE = M2.CD AND M2.TYPE_CD = 'RESHIPMENT_TYPE' LEFT JOIN T_DIS_SHIPVOYAGE_ITEM T4 ON T4. ID = T1.SHIPVOYAGE_ITEM_ID LEFT JOIN T_DIS_SHIPVOYAGE T5 ON T5.ID = T1.SHIPVOYAGE_ID LEFT JOIN M_WORK_PROCESS T8 ON T1. PROCESS_CODE = T8.PROCESS_CD LEFT JOIN (SELECT TRUST_ID,MAX(PACKING_CODE) PACKING_CODE,MAX(PACKING_NAME) PACKING_NAME FROM T_BUS_TRUST_CARGO GROUP BY TRUST_ID) tbtc2 ON TBTC2.TRUST_ID = TBT.ID LEFT JOIN ( SELECT A.TRUST_ID, LISTAGG (TO_CHAR(T6.SHIP_NAME),',') WITHIN GROUP (ORDER BY T6.SHIP_NAME) SHIP_NAME, LISTAGG (TO_CHAR(T6.CARGO_INFO_NO),',') WITHIN GROUP (ORDER BY T6.CARGO_INFO_NO) CARGO_INFO_NO, LISTAGG ( TO_CHAR (A.BUSINESS_NO),',' ) WITHIN GROUP (ORDER BY A.TRUST_ID) TRUST_INFO_NO FROM T_BUS_CARGO_INFO T6 INNER JOIN T_BUS_TRUST_CARGO A ON A .CARGO_INFO_ID = T6. ID INNER JOIN T_BUS_TRUST T5 ON T5. ID = A .TRUST_ID GROUP BY A.TRUST_ID ) tdsi ON tdsi.TRUST_ID = t1.TRUST_ID LEFT JOIN ( SELECT TBTC.TRUST_ID "trustId", TDSI.ID "id", TDS.SHIP_NAME || '_' || TDSI.VOYAGE "shipNameVoyage", TDSI.VOYAGE, TDS.SCN SCN FROM T_BUS_TRUST_CARGO TBTC JOIN T_BUS_CARGO_INFO TBCI ON TBTC.CARGO_INFO_ID = TBCI.ID JOIN T_DIS_SHIPVOYAGE TDS on TBCI.SHIPVOYAGE_ID = TDS.ID JOIN T_DIS_SHIPVOYAGE_ITEM TDSI on TBCI.SHIPVOYAGE_ITEM_ID = TDSI.ID GROUP BY TBTC.TRUST_ID, TDSI.ID, TDS.SHIP_NAME, TDSI.VOYAGE, TDS.SCN ) T7 ON T7."trustId" = t1.TRUST_ID
T1.STATUS = 20
and T1.CLASS_CODE = #{classCode}
and tbtc2.PACKING_CODE = #{packingCode}
and T1.WORK_DATE = TO_DATE(#{workDate},'YYYY-MM-DD')
and (T1.FRONT_TALLY_BY like #{loginIdLike} OR T1.BACK_TALLY_BY like #{loginIdLike} OR T1.DISPATCH_BY like #{loginIdLike})
AND ( T5.SHIP_NAME LIKE #{shipNameVoyage_like} OR tdsi.SHIP_NAME LIKE #{shipNameVoyage_like} OR T4.VOYAGE LIKE #{shipNameVoyage_like} )
AND tdsi.TRUST_INFO_NO LIKE #{businessNo_like}
AND tdsi.CARGO_INFO_NO LIKE #{cargoInfoNo_like}
AND T1.PROCESS_NAME LIKE #{processName_like}

SELECT tpps.ID "inOutId", tpps.CARGO_INFO_ID, tpps.STOREHOUSE_ID, tpps.STOREHOUSE_NAME, tpps.REGION_ID LOCATION_ID, tpps.REGION_NAME LOCATION_NO, tpps.MASS_ID STACK_POSITION_ID, tpps.MASS_NAME STACK_POSITION_NAME, tbci.CARGO_CODE, tbci.CARGO_NAME, tbci.CARGO_INFO_NO, tpps.QUANTITY quantitySurplus, tpps.TON tonSurplus, TPWPL.DIRECTION "sourceOrTargetFlag", CASE WHEN TPWPL.DIRECTION = 1 THEN '源' WHEN TPWPL.DIRECTION = 2 THEN '目标' END "sourceOrTarget" FROM T_PRD_PORT_STORAGE tpps LEFT JOIN T_BUS_CARGO_INFO tbci ON TPPS.CARGO_INFO_ID = TBCI.ID LEFT JOIN M_STORAGE_YARD msy ON msy.id = TPPS.REGION_ID LEFT JOIN T_PRD_WORK_PLAN_LOCATION tpwpl ON TPWPL.MASS_ID = TPPS.MASS_ID
AND TPWPL.WORK_PLAN_ID = #{workPlanId}
AND tbci.ID = #{cargoInfoId}
